from Crypto.Cipher import AES
from Crypto.Random import get_random_bytes
from hashlib import sha256

def encrypt_user_data(data):
    salt = get_random_bytes(16)
    password = b'your-secret-password'  # replace with your own secure password
    key = sha256((salt + password).encode()).digest()
    cipher = AES.new(key, AES.MODE_EAX, nonce=salt)
    encrypted = cipher.encrypt(data)
    return salt, encrypted, cipher.nonce